class Solution(object):
    def longestCommonPrefix(self, words, k):
        """
        :type words: List[str]
        :type k: int
        :rtype: List[int]
        """
        n = len(words)
        result = []

        class TrieNode:
            def __init__(self):
                self.children = {}
                self.count = 0  # Number of words passing through

        for remove_idx in range(n):
            # Build trie without word at remove_idx
            root = TrieNode()

            for i, word in enumerate(words):
                if i == remove_idx:
                    continue

                node = root
                for ch in word:
                    if ch not in node.children:
                        node.children[ch] = TrieNode()
                    node = node.children[ch]
                    node.count += 1

            # Find longest common prefix with count >= k
            max_prefix = 0
            node = root
            depth = 0

            while node.children:
                # Find child with count >= k
                found = False
                for ch in sorted(node.children.keys()):
                    child = node.children[ch]
                    if child.count >= k:
                        node = child
                        depth += 1
                        found = True
                        break

                if found and node.count >= k:
                    max_prefix = depth
                else:
                    break

            result.append(max_prefix)

        return result
